import{c as r,bq as s,bj as i,aQ as n,aT as t,aV as o,U as l,ai as c,a9 as d,ar as h}from"./chunks/framework.BSLq2HW8.js";const E=JSON.parse('{"title":"Form Error Message","description":"","frontmatter":{},"headers":[],"relativePath":"documentation/field-types/advance/form-error-message.md","filePath":"documentation/field-types/advance/form-error-message.md","lastUpdated":1770573358000}'),p={name:"documentation/field-types/advance/form-error-message.md"};function g(m,e,u,f,y,b){const a=s("Badge");return i(),n("div",null,[e[0]||(e[0]=t('<h1 id="form-error-message" tabindex="-1">Form Error Message <a class="header-anchor" href="#form-error-message" aria-label="Permalink to “Form Error Message”">​</a></h1><p>This field type allows you to detect and handle error messages that appear on the page after form submission. It works similarly to <a href="/documentation/form-response/form-error-response.html">Form Error Response</a>, but <strong>does not check URLs</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Key Difference</p><p>Unlike Form Error Response, this field type:</p><ul><li><strong>Does NOT use</strong> &quot;Error Page URL&quot; option</li><li><strong>Does NOT use</strong> &quot;Match URL Types&quot; option</li><li>Works on the current page without URL validation</li></ul></div><h2 id="when-to-use" tabindex="-1">🎯 When to Use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to “🎯 When to Use”">​</a></h2><p>Use this field type when you want to:</p><ul><li>Detect error messages that appear on the same page (no redirect)</li><li>Handle multiple error messages in different locations on the page</li><li>Stop or save the entry based on error detection</li><li>Use it as a field within your form configuration</li></ul><div class="info custom-block"><p class="custom-block-title">Multiple Error Messages</p><p>If multiple error messages can appear in different locations on the page, this field type can match <strong>any of them</strong> regardless of their position.</p></div><h2 id="field-options" tabindex="-1">⚙️ Field Options <a class="header-anchor" href="#field-options" aria-label="Permalink to “⚙️ Field Options”">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><a href="#error-response-type">Error Response Type</a></td><td>The type of error message that appears on the page</td></tr><tr><td><a href="#enter-error-message">Enter Error Message</a></td><td>The error message to match after form submission</td></tr><tr><td><a href="#entry-action-type">Entry Action Type</a></td><td>What to do when error is detected (stop or save)</td></tr><tr><td><a href="#delay-time-before-run-action">Delay Time Before Run Action</a></td><td>Time delay before the <a href="#action">action</a> is executed</td></tr><tr><td><a href="#action">Action</a></td><td>Action to execute when the error response matches</td></tr></tbody></table><h2 id="additional-options" tabindex="-1">📋 Additional Options <a class="header-anchor" href="#additional-options" aria-label="Permalink to “📋 Additional Options”">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>If excel data is not found then don&#39;t execute the action</td><td>Prevents action execution when Excel data is empty</td></tr><tr><td>If last excel entry completed then don&#39;t execute the action</td><td>Prevents action execution after the last entry is completed</td></tr><tr><td>If there is no Excel data, update only scraper data in Excel</td><td>Saves only scraped data when no Excel template is used</td></tr><tr><td>Can error message be anything in this element</td><td>Matches any message in the given element (useful for dynamic messages)</td></tr><tr><td>Remove excel column value from current entry?</td><td>Removes column value from current entry after processing</td></tr><tr><td>Set custom message after error message matched?</td><td>Sets a custom short message instead of the full error message</td></tr></tbody></table><h2 id="error-response-type" tabindex="-1">🔍 Error Response Type <a class="header-anchor" href="#error-response-type" aria-label="Permalink to “🔍 Error Response Type”">​</a></h2><p>Choose how the extension should detect the error response:</p><h3 id="matching-message-in-page" tabindex="-1">1. Matching Message In Page <a class="header-anchor" href="#matching-message-in-page" aria-label="Permalink to “1. Matching Message In Page”">​</a></h3><p>Searches for the error message anywhere in the page content.</p><p><strong>Options:</strong></p><ul><li><strong>Message Selector Query</strong> (optional): Limit the search to a specific element</li></ul><img src="'+l+'" alt="Error Message in Page"><div class="tip custom-block"><p class="custom-block-title">Multiple Locations</p><p>This is especially useful when error messages can appear in different locations on the page. The extension will search the entire page by default.</p></div><h3 id="matching-message-in-alert" tabindex="-1">2. Matching Message In Browser Alert <a class="header-anchor" href="#matching-message-in-alert" aria-label="Permalink to “2. Matching Message In Browser Alert”">​</a></h3><p>Detects error messages that appear in JavaScript alert dialogs.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Enable <a href="/documentation/settings.html#hide-javascript-dialog">Hide JavaScript Dialog</a> in settings to automatically handle alerts.</p></div><img src="'+c+'" alt="Alert Dialog"><h3 id="matching-message-in-element-value" tabindex="-1">3. Matching Message In Page Element Value <a class="header-anchor" href="#matching-message-in-element-value" aria-label="Permalink to “3. Matching Message In Page Element Value”">​</a></h3><p>Checks for the error message in a form field&#39;s value (e.g., input box).</p><p><strong>Required:</strong></p><ul><li><strong>Message Selector Query</strong>: The selector of the input element</li></ul><img src="'+d+'" width="500" height="500" alt="Element Value"><h3 id="checking-element-exists" tabindex="-1">4. Checking Element Exists In Page <a class="header-anchor" href="#checking-element-exists" aria-label="Permalink to “4. Checking Element Exists In Page”">​</a></h3><p>Marks entry as having an error when a specific element appears on the page.</p><p><strong>Required:</strong></p><ul><li><strong>Message Selector Query</strong>: The selector of the element to check</li></ul><div class="warning custom-block"><p class="custom-block-title">Important</p><p>The element should NOT be present before submission and should only appear after an error occurs.</p></div><h2 id="enter-error-message" tabindex="-1">📝 Enter Error Message <a class="header-anchor" href="#enter-error-message" aria-label="Permalink to “📝 Enter Error Message”">​</a></h2><p>Enter the error message(s) to match. You can add multiple messages - if any matches, the extension will handle the error according to your <a href="#entry-action-type">Entry Action Type</a>.</p><p><strong>Features:</strong></p><ul><li>Support for multiple messages</li><li>Dynamic message support using variables</li><li>Partial message matching</li></ul><p><strong>Example:</strong></p><img src="'+h+'" alt="Error Messages"><details class="details custom-block"><summary>Dynamic Error Messages</summary><p>Use Excel column variables in your error messages:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Error: {$Email$} is already registered</span></span></code></pre></div><p>Or use partial matching:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>already registered</span></span></code></pre></div><p>This will match any error message containing &quot;already registered&quot;.</p></details><details class="details custom-block"><summary>Pre-existing Error Messages</summary><p>If an error message is already present on the page <strong>before</strong> form submission, the extension will detect it and <strong>will not fill the entry</strong> to prevent duplicate submissions.</p></details><h2 id="entry-action-type" tabindex="-1">🎬 Entry Action Type <a class="header-anchor" href="#entry-action-type" aria-label="Permalink to “🎬 Entry Action Type”">​</a></h2><p>Choose what happens when an error message is detected:</p><h3 id="_1-stop-entry" tabindex="-1">1. Stop Entry <a class="header-anchor" href="#_1-stop-entry" aria-label="Permalink to “1. Stop Entry”">​</a></h3><ul><li>Stops processing the current entry</li><li>Entry is NOT marked as saved</li><li>Useful when you want to manually fix the issue</li></ul><h3 id="_2-save-error-in-the-entry-data" tabindex="-1">2. Save Error in the Entry Data <a class="header-anchor" href="#_2-save-error-in-the-entry-data" aria-label="Permalink to “2. Save Error in the Entry Data”">​</a></h3><ul><li>Marks the entry as saved</li><li>Stores the error message in the Excel entry</li><li>Continues to the next entry</li><li>Useful for logging errors and reviewing later</li></ul><h2 id="delay-time-before-run-action" tabindex="-1">⏱️ Delay Time Before Run Action <a class="header-anchor" href="#delay-time-before-run-action" aria-label="Permalink to “⏱️ Delay Time Before Run Action”">​</a></h2><p>Set a delay (in milliseconds) before executing the action.</p>',49)),o(a,{type:"tip",text:"1 second = 1000 milliseconds"}),e[1]||(e[1]=t(`<h2 id="action" tabindex="-1">🚀 Action <a class="header-anchor" href="#action" aria-label="Permalink to “🚀 Action”">​</a></h2><p>Choose what happens after the error message is matched:</p><ul><li><strong>Redirect to Page</strong> - Navigate to a different page</li><li><strong>Re-Execute Form</strong> - Fill the form again (useful for retrying)</li><li><strong>Click on Button</strong> - Click a specific button element</li><li><strong>Page Reload</strong> - Reload the current page</li><li><strong>Execute Segment</strong> - Run a specific segment of fields</li></ul><h2 id="important-notes" tabindex="-1">⚠️ Important Notes <a class="header-anchor" href="#important-notes" aria-label="Permalink to “⚠️ Important Notes”">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Critical</p><p>When you use this field type, <strong>all fields below it will NOT execute</strong>. Always place this field type <strong>at the end</strong> of your field list.</p></div><p><strong>Execution Flow:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Field 1 ✅ Executes</span></span>
<span class="line"><span>Field 2 ✅ Executes</span></span>
<span class="line"><span>Field 3 ✅ Executes</span></span>
<span class="line"><span>Form Error Message ✅ Executes &amp; Detects Error</span></span>
<span class="line"><span>Field 4 ❌ Does NOT Execute</span></span>
<span class="line"><span>Field 5 ❌ Does NOT Execute</span></span></code></pre></div><h2 id="use-cases" tabindex="-1">💡 Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to “💡 Use Cases”">​</a></h2><h3 id="handling-variable-error-locations" tabindex="-1">Handling Variable Error Locations <a class="header-anchor" href="#handling-variable-error-locations" aria-label="Permalink to “Handling Variable Error Locations”">​</a></h3><p>If your form shows errors in different places depending on the error type:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Login Error: Top of page</span></span>
<span class="line"><span>Validation Error: Next to field</span></span>
<span class="line"><span>Server Error: Modal popup</span></span></code></pre></div><p>This field type can detect all of them without specifying exact locations.</p><h3 id="logging-errors-for-review" tabindex="-1">Logging Errors for Review <a class="header-anchor" href="#logging-errors-for-review" aria-label="Permalink to “Logging Errors for Review”">​</a></h3><p>Set <strong>Entry Action Type</strong> to &quot;Save Error in the Entry Data&quot; to:</p><ol><li>Continue processing all entries</li><li>Mark entries with errors</li><li>Review and fix them later in Excel</li></ol><h3 id="retry-on-temporary-errors" tabindex="-1">Retry on Temporary Errors <a class="header-anchor" href="#retry-on-temporary-errors" aria-label="Permalink to “Retry on Temporary Errors”">​</a></h3><p>Set <strong>Action</strong> to &quot;Re-Execute Form&quot; to automatically retry when temporary errors occur (e.g., network issues).</p><h2 id="related" tabindex="-1">🔗 Related Documentation <a class="header-anchor" href="#related" aria-label="Permalink to “🔗 Related Documentation”">​</a></h2><ul><li><a href="/documentation/form-response/form-error-response.html">Form Error Response</a> - Similar functionality with URL checking</li><li><a href="/documentation/field-types/advance/current-entry-as-saved.html">Current Entry as Saved</a> - Handle success responses</li><li><a href="/documentation/form-response/form-success-response.html">Form Success Response</a> - Success handling with URL checking</li></ul>`,19))])}const x=r(p,[["render",g]]);export{E as __pageData,x as default};
